// Parsear respuesta de OpenAI
const inputData = $input.item.json;

// Intentar múltiples formas de obtener la respuesta
let response = null;

// Forma 1: message.content (nueva API)
if (inputData.message && inputData.message.content) {
  response = inputData.message.content;
}
// Forma 2: choices[0].message.content (API antigua)
else if (inputData.choices && inputData.choices.length > 0 && inputData.choices[0].message) {
  response = inputData.choices[0].message.content;
}
// Forma 3: text (completions API)
else if (inputData.text) {
  response = inputData.text;
}
// Forma 4: content directo
else if (inputData.content) {
  response = inputData.content;
}

// Validar que hay respuesta
if (!response) {
  throw new Error('OpenAI no devolvió respuesta válida. Data recibida: ' + JSON.stringify(inputData));
}

let analisisIA;
try {
  // Extraer JSON de la respuesta (puede venir con markdown)
  const jsonMatch = response.match(/\{[\s\S]*\}/);

  if (!jsonMatch) {
    throw new Error('No se encontró JSON en la respuesta. Respuesta: ' + response);
  }

  analisisIA = JSON.parse(jsonMatch[0]);
} catch (error) {
  return {
    error: true,
    mensaje: "No se pudo parsear la respuesta de OpenAI",
    respuesta_raw: response,
    error_detalle: error.message,
    input_completo: inputData
  };
}

// Combinar con datos del email original
const emailOriginal = $('📧 Gmail: Recibir Solicitud').item.json;

return {
  ...analisisIA,
  email_remitente: emailOriginal.from || 'desconocido',
  asunto_original: emailOriginal.subject || 'sin asunto',
  fecha_recepcion: new Date().toISOString(),
  email_completo: emailOriginal.text || emailOriginal.textPlain || ''
};

// VALIDACIÓN ADICIONAL: Detectar cancelación por palabras clave
const emailTexto = emailOriginal.text || emailOriginal.textPlain || '';
const textoMinusculas = emailTexto.toLowerCase();

if ((textoMinusculas.includes('cancelar') || 
     textoMinusculas.includes('cancel') || 
     textoMinusculas.includes('dar de baja') ||
     textoMinusculas.includes('baja de cuenta')) &&
    analisisIA.tipo_solicitud === 'OTRO') {

  console.log('⚠️ CORRECCIÓN: Detectado "cancelar" pero IA lo marcó como OTRO');
  analisisIA.tipo_solicitud = 'CANCELACION';
  analisisIA.cumple_politica = true;
  analisisIA.razon_cumplimiento = 'Solicitud de cancelación detectada por palabra clave';
  analisisIA.respuesta_sugerida = 'Hemos recibido tu solicitud de cancelación.';
}

// Combinar con datos del email original
return {
  ...analisisIA,
  email_remitente: emailOriginal.from || 'desconocido',
  asunto_original: emailOriginal.subject || 'sin asunto',
  fecha_recepcion: new Date().toISOString(),
  email_completo: emailOriginal.text || emailOriginal.textPlain || ''
};

const analisisIA = $input.item.json;
let emailBusqueda = analisisIA.email_cliente;
if (analisisIA.email_pago && analisisIA.email_pago !== analisisIA.email_cliente) {
  emailBusqueda = analisisIA.email_pago;
}
return { email_busqueda: emailBusqueda, ...analisisIA };

const analisisIA = $('📝 Parsear Respuesta IA').item.json;
const lookupData = $('🔍 Brain Metric: Buscar Cliente1').item.json;

if (!lookupData.found) {
  return { cumple_politica: false, razon: "Cliente no encontrado", ...analisisIA };
}

const hasActive = lookupData.has_active_subscription;
const status = lookupData.subscription_status;

if (analisisIA.tipo_solicitud === "REEMBOLSO_INICIAL") {
  return {
    ...analisisIA,
    cumple_politica: false,
    razon: "El pago inicial NO es reembolsable - contenido digital ya entregado",
    customer_email: lookupData.email,
    tipo: "REEMBOLSO_INICIAL"
  };
}

if (analisisIA.tipo_solicitud === "REEMBOLSO_SUSCRIPCION") {
  const motivosValidos = ["indisponibilidad", "problemas técnicos", "error de facturación", "cargo duplicado", "no funciona", "caída", "down", "bug"];
  const motivoValido = motivosValidos.some(m => analisisIA.motivo_solicitud.toLowerCase().includes(m));

  if (motivoValido) {
    return {
      ...analisisIA,
      cumple_politica: true,
      razon: "Motivo técnico válido: " + analisisIA.motivo_solicitud,
      customer_email: lookupData.email,
      monto_total: 1999,
      tipo: "REEMBOLSO_SUSCRIPCION",
      ofrecer_cancelacion: hasActive
    };
  } else {
    return {
      ...analisisIA,
      cumple_politica: false,
      razon: "Motivo no cumple con política de reembolsos",
      customer_email: lookupData.email,
      ofrecer_cancelacion: hasActive
    };
  }
}

if (analisisIA.tipo_solicitud === "CANCELACION") {
  if (!hasActive) {
    return { ...analisisIA, cumple_politica: false, razon: "No tiene suscripción activa", tipo: "CANCELACION" };
  }
  return {
    ...analisisIA,
    cumple_politica: true,
    razon: "Solicitud de cancelación - siempre permitida",
    customer_email: lookupData.email,
    tipo: "CANCELACION",
    solo_cancelar: true
  };
}

return { ...analisisIA, cumple_politica: false, razon: "No cumple con criterios de reembolso" };

